import React from 'react';

function Navbar() {
  const token = localStorage.getItem('token');

  const handleLogout = () => {
    localStorage.removeItem('token');
    window.location.href = '/login';
  };

  return (
    <nav style={{ background: '#333', padding: '10px', display: 'flex', gap: '20px' }}>
      <a href="/" style={{ color: 'white', textDecoration: 'none' }}>Home</a>
      <a href="/create" style={{ color: 'white', textDecoration: 'none' }}>Create Blog</a>
      {token ? (
        <button onClick={handleLogout} style={{ background: 'red', color: 'white', border: 'none', padding: '5px 10px', cursor: 'pointer' }}>Logout</button>
      ) : (
        <>
          <a href="/login" style={{ color: 'white', textDecoration: 'none' }}>Login</a>
          <a href="/register" style={{ color: 'white', textDecoration: 'none' }}>Register</a>
        </>
      )}
    </nav>
  );
}

export default Navbar;
